/// The 0x80..=0xFF table for a single-byte ANSI code page, or `None` for a page that is not
/// a known single byte (e.g. the double-byte CJK pages, or Windows-1252 which decode.rs owns).
pub(crate) fn single_byte_high(code_page: u16) -> Option<&'static [char; 128]> {
    Some(match code_page {
        1250 => &CP1250_HIGH,
        1251 => &CP1251_HIGH,
        1253 => &CP1253_HIGH,
        1254 => &CP1254_HIGH,
        1255 => &CP1255_HIGH,
        1256 => &CP1256_HIGH,
        1257 => &CP1257_HIGH,
        1258 => &CP1258_HIGH,
        874 => &CP874_HIGH,
        _ => return None,
    })
}
